/**
 * 首頁畫面元件
 */
import { LEVELS, TIMERS, ALL_CHARS } from '../data/gameEngine';

export default function HomeScreen({
  lang, t, setLang,
  level, setLevel,
  timerValue, setTimerValue,
  importText, setImportText,
  showImportModal, setShowImportModal,
  onStartNormal, onStartForge, onStartPolyphone, onImport,
}) {
  return (
    <>
      <div className="header">
        <button className="lang-toggle-btn" onClick={() => setLang(l => l === "zh" ? "en" : "zh")} style={{ position: 'absolute', right: 0, top: '24px', background: 'white', border: '2px solid #e8e0d0', padding: '4px 12px', borderRadius: '16px', cursor: 'pointer', fontFamily: 'inherit', color: '#5d4037', transition: 'all 0.2s' }}>
          🌐 {t.langToggle}
        </button>
        <h1>{t.title}</h1>
        <div className="subtitle" dangerouslySetInnerHTML={{ __html: t.subtitle.replace("{{count}}", ALL_CHARS.length) }} />
      </div>

      {/* RPG 難度選擇 */}
      <div className="level-grid">
        {LEVELS.map(lv => (
          <button
            key={lv.id}
            className={`level-btn ${level === lv.id ? "active" : ""}`}
            onClick={() => setLevel(lv.id)}
          >
            <span className="lv-emoji">{lv.emoji}</span>
            <span className="lv-name">Lv.{lv.id} {t.levelNames[lv.id]}</span>
            <span className="lv-range">{t.levelDesc.replace("{{count}}", lv.maxFreq === 99999 ? ALL_CHARS.length : lv.maxFreq)}</span>
          </button>
        ))}
      </div>

      {/* 時間設定 */}
      <div className="timer-section">
        <h4>{t.timerTitle}</h4>
        <div className="timer-grid">
          {TIMERS.map(timer => (
            <button
              key={timer.value}
              className={`timer-btn ${timerValue === timer.value ? "active" : ""}`}
              onClick={() => setTimerValue(timer.value)}
            >
              {t.timers[timer.value].label} {t.timers[timer.value].tag && <small>({t.timers[timer.value].tag})</small>}
            </button>
          ))}
        </div>
      </div>

      {/* 主按鈕 */}
      <button className="start-btn" onClick={onStartNormal}>
        {t.startQuiz}
      </button>

      {/* 次要功能並排 */}
      <div className="secondary-btns">
        <button className="secondary-game-btn forge-mini" onClick={onStartForge}>
          <span className="sg-icon">🔨</span>
          <span className="sg-label">{lang === "zh" ? "造字工坊" : "Forge"}</span>
        </button>
        <button className="secondary-game-btn poly-mini" onClick={onStartPolyphone}>
          <span className="sg-icon">🔮</span>
          <span className="sg-label">{lang === "zh" ? "變聲秘術" : "Polyphone"}</span>
        </button>
        <button className="secondary-game-btn import-mini" onClick={() => setShowImportModal(true)}>
          <span className="sg-icon">📜</span>
          <span className="sg-label">{lang === "zh" ? "自訂魔物" : "Custom"}</span>
        </button>
      </div>

      {/* 自訂魔物 Modal */}
      {showImportModal && (
        <div className="modal-overlay" onClick={() => setShowImportModal(false)}>
          <div className="modal-box" style={{ maxWidth: '440px' }} onClick={e => e.stopPropagation()}>
            <h3>📜 {t.importTitle}</h3>
            <p style={{ textAlign: 'left', fontSize: '0.82rem', color: '#999', lineHeight: 1.6 }}>{t.importDesc}</p>
            <textarea
              className="import-textarea"
              placeholder={t.importPlaceholder}
              value={importText}
              onChange={e => setImportText(e.target.value)}
              style={{ height: '140px', marginTop: '8px' }}
            />
            <div className="modal-actions" style={{ marginTop: '12px' }}>
              <button className="btn-secondary" onClick={() => setShowImportModal(false)}>
                {lang === "zh" ? "取消" : "Cancel"}
              </button>
              <button className="btn-primary" onClick={() => { onImport(); setShowImportModal(false); }} disabled={!importText.trim()}>
                {t.importBtn}
              </button>
            </div>
          </div>
        </div>
      )}
    </>
  );
}
